import asyncio
from typing import Dict, List, Tuple

class PlayerState:
    def __init__(self, name: str, coordinates: Tuple[int, int, int]):
        self.name = name
        self.coordinates = coordinates

class GameServer:
    def __init__(self):
        self.players: Dict[str, PlayerState] = {}
        self.clients: List[asyncio.StreamWriter] = []
      
    async def handle_connection(self, reader: asyncio.StreamReader, writer: asyncio.StreamWriter):
        self.clients.append(writer)
        player_name = await reader.read(100)

        while True:
            line = await reader.read(100) 
            if not line:
                break

            state = self.parse_state(line)
            self.players[player_name] = state
            
            await self.broadcast_state()
 
        self.clients.remove(writer)
        del self.players[player_name]
        writer.close()
  
    def parse_state(self, data: bytes) -> PlayerState:
        data = data.decode()
        name, x, y, z = data.split(",")
        return PlayerState(name, (int(x), int(y), int(z)))
       
    async def broadcast_state(self):
        for client in self.clients:
            for player, state in self.players.items():
                client.write(f"{player},{state.coordinates[0]},{state.coordinates[1]},{state.coordinates[2]}\n".encode())
            await client.drain()

server = GameServer()
loop = asyncio.get_event_loop()
loop.create_task(asyncio.start_server(server.handle_connection, '127.0.0.1', 5000))
loop.run_forever()